import { useEffect, useState } from "react";
import {
  BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer,
  PieChart, Pie, Cell, LineChart, Line, CartesianGrid, Legend
} from "recharts";
import { fetchStats } from "../api";

const COLORS = { Clean: "#4ade80", Dirty: "#f87171" };

export default function StatsTab() {
  const [stats,   setStats]   = useState(null);
  const [loading, setLoading] = useState(true);
  const [error,   setError]   = useState(null);

  useEffect(() => {
    fetchStats()
      .then(setStats)
      .catch(e => setError(e.message))
      .finally(() => setLoading(false));
  }, []);

  if (loading) return <div className="tab-container"><p>Loading statistics…</p></div>;
  if (error)   return <div className="tab-container"><div className="error-box">⚠ {error}</div></div>;
  if (!stats?.summary) return <div className="tab-container"><p>No stats data found. Run evaluate.py first.</p></div>;

  const summary     = stats.summary;
  const tests       = stats.tests;
  const uncertainty = stats.uncertainty;

  // Derived data for charts
  const correct   = summary.filter(d => d.correct).length;
  const total     = summary.length;
  const cleanCount= summary.filter(d => d.predicted === "Clean").length;
  const dirtyCount= summary.filter(d => d.predicted === "Dirty").length;

  const pieData = [
    { name: "Clean", value: cleanCount },
    { name: "Dirty", value: dirtyCount }
  ];

  const confBins = ["0.5–0.6","0.6–0.7","0.7–0.8","0.8–0.9"];
  const confData = confBins.map((bin, i) => {
    const lo = 0.5 + i * 0.1, hi = lo + 0.1;
    const inBin = summary.filter(d => d.confidence >= lo && d.confidence < hi + 0.01);
    return {
      bin,
      count:    inBin.length,
      accuracy: inBin.length
        ? Math.round(inBin.filter(d => d.correct).length / inBin.length * 100)
        : 0
    };
  });

  const uncData = uncertainty
    ? [...uncertainty]
        .sort((a, b) => a.uncertainty_std - b.uncertainty_std)
        .map((d, i) => ({
          idx:     i + 1,
          unc:     +(d.uncertainty_std * 100).toFixed(2),
          entropy: +(d.predictive_entropy * 100).toFixed(2),
          correct: d.correct
        }))
    : [];

  return (
    <div className="tab-container">
      <h2 className="tab-title">Model statistics</h2>

      {/* Top metric cards */}
      <div className="cards-row">
        {[
          { label: "Accuracy",   value: `${(correct/total*100).toFixed(1)}%` },
          { label: "ROC-AUC",    value: "0.8997" },
          { label: "Dirty F1",   value: "85.71%" },
          { label: "Test images",value: total },
        ].map(c => (
          <div key={c.label} className="stat-card">
            <div className="stat-label">{c.label}</div>
            <div className="stat-value">{c.value}</div>
          </div>
        ))}
      </div>

      {/* Statistical test results */}
      {tests && (
        <div className="section">
          <h3 className="section-title">Statistical tests</h3>
          <div className="cards-row">
            <div className="test-card pass">
              <div className="test-name">Binomial test</div>
              <div className="test-stat">p = {tests.binomial_test.p_value}</div>
              <div className="test-verdict">Significantly better than chance ✓</div>
            </div>
            <div className="test-card pass">
              <div className="test-name">McNemar's test</div>
              <div className="test-stat">p = {tests.mcnemar_test.p_value}</div>
              <div className="test-verdict">Significantly better than baseline ✓</div>
            </div>
            <div className="test-card info">
              <div className="test-name">Bootstrap 95% CI</div>
              <div className="test-stat">
                [{(tests.bootstrap_ci.accuracy.ci_low*100).toFixed(1)}% –{" "}
                {(tests.bootstrap_ci.accuracy.ci_high*100).toFixed(1)}%]
              </div>
              <div className="test-verdict">Accuracy confidence interval</div>
            </div>
          </div>
        </div>
      )}

      {/* Charts row 1 */}
      <div className="charts-row">
        <div className="chart-card">
          <h3 className="chart-title">Prediction distribution</h3>
          <ResponsiveContainer width="100%" height={200}>
            <PieChart>
              <Pie data={pieData} cx="50%" cy="50%" outerRadius={70}
                   dataKey="value" label={({ name, value }) => `${name}: ${value}`}>
                {pieData.map(entry => (
                  <Cell key={entry.name} fill={COLORS[entry.name]} />
                ))}
              </Pie>
              <Tooltip />
            </PieChart>
          </ResponsiveContainer>
        </div>

        <div className="chart-card">
          <h3 className="chart-title">Calibration: confidence vs accuracy</h3>
          <ResponsiveContainer width="100%" height={200}>
            <BarChart data={confData}>
              <CartesianGrid strokeDasharray="3 3" stroke="#2d3748" />
              <XAxis dataKey="bin" tick={{ fontSize: 11 }} />
              <YAxis tick={{ fontSize: 11 }} />
              <Tooltip />
              <Legend />
              <Bar dataKey="count"    fill="#818cf8" name="Count" />
              <Bar dataKey="accuracy" fill="#4ade80" name="Accuracy %" />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Charts row 2 */}
      {uncData.length > 0 && (
        <div className="chart-card full-width">
          <h3 className="chart-title">Per-image uncertainty (sorted)</h3>
          <ResponsiveContainer width="100%" height={200}>
            <LineChart data={uncData}>
              <CartesianGrid strokeDasharray="3 3" stroke="#2d3748" />
              <XAxis dataKey="idx" tick={{ fontSize: 11 }} label={{ value: "Image index", position: "insideBottom", offset: -2, fontSize: 11 }} />
              <YAxis tick={{ fontSize: 11 }} />
              <Tooltip />
              <Legend />
              <Line type="monotone" dataKey="unc"     stroke="#38bdf8" dot={false} name="Uncertainty (std ×100)" />
              <Line type="monotone" dataKey="entropy" stroke="#a78bfa" dot={false} name="Entropy ×100" />
            </LineChart>
          </ResponsiveContainer>
        </div>
      )}
    </div>
  );
}
